        old_entry = self._entries[task_id]
        updated_task = replace(task, priority=priority)
        new_entry = (-priority, old_entry[1], task_id)

        self._tasks[task_id] = updated_task
        self._entries[task_id] = new_entry
        heappush(self._heap, new_entry)

        return updated_task

    def list_tasks(self, *, priority: int | None = None) -> list[Task[T]]:
        """Return pending tasks in dequeue order.

        Args:
            priority: Optional priority level to filter by.
