        return len(self) == 0

    def clear(self) -> None:
        """Remove all pending tasks from the queue."""
        self._heap.clear()
        self._entries.clear()
        self._tasks.clear()
        self._counter = count()

    def _sort_key(self, task: Task[T]) -> tuple[int, int]:
        """Return the stable ordering key for a pending task."""
        return -task.priority, self._entries[task.id][1]

